import json
import re

# Get the articles
articles = locals()['var_functions.query_db:12']

# Categories mapping
categories = ['World', 'Sports', 'Business', 'Science/Technology']

# Function to categorize based on title/description
def categorize_article(title, description):
    text = (title + ' ' + description).lower()

    # Science/Technology indicators
    science_tech_keywords = [
        'game', 'gameboy', 'technology', 'science', 'research', 'laboratory', 
        'university', 'competition', 'energy', 'electricity', 'wave', 'gyro',
        'innovative', 'prize', 'award', 'math', 'technology'
    ]

    sports_keywords = ['football', 'basketball', 'baseball', 'soccer', 'game', 'pro bowl', 'cornerback', 'broncos', 'practice', 'wide receiver']

    business_keywords = ['china', 'appetite', 'boosts', 'bhp', 'billiton', 'mining', 'company', 'profits', 'commodity', 'prices', 'business']

    world_keywords = ['china', 'world', 'global', 'international']

    # Check each category
    for keyword in science_tech_keywords:
        if keyword in text:
            return 'Science/Technology'

    for keyword in sports_keywords:
        if keyword in text:
            return 'Sports'

    for keyword in business_keywords:
        if keyword in text:
            return 'Business'

    for keyword in world_keywords:
        if keyword in text:
            return 'World'

    return 'World'  # default

# Categorize each article
categorized = []
for article in articles:
    category = categorize_article(article['title'], article['description'])
    categorized.append({
        'article_id': article['article_id'],
        'title': article['title'],
        'category': category
    })

# Count Science/Technology articles
science_tech_count = sum(1 for a in categorized if a['category'] == 'Science/Technology')
total_count = len(categorized)

result = {
    'total_articles': total_count,
    'science_tech_count': science_tech_count,
    'fraction': science_tech_count / total_count if total_count > 0 else 0
}

print('__RESULT__:')
print(json.dumps(result))
