import json

# Collect all retrieved articles from Amy Jones
def read_file_or_use_var(var_name):
    values = locals()
    if var_name in values:
        result = values[var_name]
        if isinstance(result, str) and (result.endswith('.json') or '/' in result):
            try:
                with open(result, 'r') as f:
                    return json.load(f)
            except:
                return []
        elif isinstance(result, list):
            return result
    return []

all_articles = []

# Get all chunks
def is_file_path(x):
    return isinstance(x, str) and (x.endswith('.json') or '/' in x)

# Check each variable and read if it's a file path
for i in range(70, 90):
    var_name = f'var_functions.query_db:{i}'
    if var_name in locals():
        value = locals()[var_name]
        if is_file_path(value):
            try:
                with open(value, 'r') as f:
                    all_articles.extend(json.load(f))
            except:
                pass
        elif isinstance(value, list):
            all_articles.extend(value)

# Remove duplicates by article_id
unique_articles = {}
for article in all_articles:
    unique_articles[article['article_id']] = article

final_articles = list(unique_articles.values())

# Read metadata
with open(locals()['var_functions.query_db:26'], 'r') as f:
    metadata = json.load(f)

print('__RESULT__:')
print(json.dumps({
    'total_articles_retrieved': len(final_articles),
    'total_in_metadata': len(metadata),
    'article_ids': sorted([a['article_id'] for a in final_articles], key=int)[:20]
}))
