                    data = json.load(f)
                    for article in data:
                        if 'article_id' in article:
                            all_articles.append(article)
            elif isinstance(value, list):
                for article in value:
                    if 'article_id' in article:
                        all_articles.append(article)
        except:
            pass

# Also include earlier results
for i in [38, 56, 60, 66]:
    var_name = f'var_functions.query_db:{i}'
